"use strict";parserFactory.register("novelsemperor.com",()=>new NovelsemperorParser),parserFactory.register("novelsemperor.net",()=>new NovelsemperorParser);class NovelsemperorParser extends Parser{constructor(){super()}async getChapterUrls(e,r){return(await this.walkTocPages(e,NovelsemperorParser.chaptersFromDom,NovelsemperorParser.nextTocPageUrl,r)).reverse()}static chaptersFromDom(e){return[...e.querySelectorAll("#chapters-list a")].map(NovelsemperorParser.hyperlinkToChapter)}static hyperlinkToChapter(e){return{sourceUrl:e.href,title:e.querySelector("span").innerText.trim()}}static nextTocPageUrl(e){let r=e.querySelector("ul.pagination");return null===r?null:[...r.querySelectorAll("li.pagination-link")]?.pop()?.getAttribute("onclick")?.split("'")?.[1]?.replace("//","https://")}findContent(e){return e.querySelector("div.chap-content")}extractTitleImpl(e){return e.querySelector("h2")}findChapterTitle(e){return e.querySelector("h2")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"main")}getInformationEpubItemChildNodes(e){return[e.querySelector("#description").parentElement]}}